import java.util.Map;

public class Solution {
    public static long solve(long[][] points) {
        final long MOD = 1_000_000_007;
        long inv_2 = 500_000_004; // Modular inverse of 2 modulo 1e9+7

        Map<Long, Long> yCounts = new HashMap<>();
        for (long[] p : points) {
            long y = p[1];
            yCounts.put(y, yCounts.getOrDefault(y, 0L) + 1);
        }

        long totalSum = 0;
        long sumSquares = 0;

        for (Long count : yCounts.values()) {
            long term = count * (count - 1);
            term = term % MOD;
            term = term * inv_2 % MOD;
            totalSum = (totalSum + term) % MOD;

            long termSquare = term * term % MOD;
            sumSquares = (sumSquares + termSquare) % MOD;
        }

        long totalSumSquared = (totalSum * totalSum) % MOD;
        long temp = (totalSumSquared - sumSquares + MOD) % MOD;
        long ans = (temp * inv_2) % MOD;

        return ans;
    }
}
